	ctx, cancel := context.WithTimeout(ctx, 5*time.Second)
	defer cancel()

	select {
	case f := <-fixes:
		fmt.Println("got fix:", f)
	case <-ctx.Done():
		fmt.Println("gave up:", ctx.Err())
	}
}

