package tracking

import "sync"

// Fan-in: merge many channels into one.
func merge(cs ...<-chan int) <-chan int {
	out := make(chan int)
	var wg sync.WaitGroup

	for _, c := range cs {
		wg.Add(1)
		go func(c <-chan int) {
			defer wg.Done()
			for v := range c {
				out <- v
			}
		}(c)
	}

	// One closer goroutine: wait for every forwarder, then close out.
	go func() { wg.Wait(); close(out) }()

	return out
}

